        let afterLocalExpiry = try await connector.fetchUsages()
        #expect(afterLocalExpiry[0].lastError?.type == "token_expired")
        assertPreserved(afterLocalExpiry[0].metrics, against: Self.expectedSeeded, context: "after locator tokenExpired")
    }

    @Test("401 → 429 → 429 cascade must not erode metrics across iterations")
    func cascadeDoesNotErodeMetrics() async throws {
        let dir = makeTempDir()
